diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index d824c40c401d..e913d4583bf3 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -9773,7 +9773,10 @@ class BoUpSLP::ShuffleCostEstimator : public BaseShuffleAnalysis {
       // Check that if trying to permute same single/2 input vectors.
       TTI::ShuffleKind ShuffleKind = TTI::SK_PermuteSingleSrc;
       int FirstRegId = -1;
-      Indices.assign(1, OffsetReg0);
+      Indices.assign(1, std::min<unsigned>(OffsetReg0 % NumElts,
+                                      (alignTo(NumElts, EltsPerVector) > EltsPerVector)
+                                          ? (alignTo(NumElts, EltsPerVector) - EltsPerVector)
+                                          : 0u));
       for (auto [Pos, I] : enumerate(Mask)) {
         if (I == PoisonMaskElem)
           continue;
@@ -9801,7 +9804,10 @@ class BoUpSLP::ShuffleCostEstimator : public BaseShuffleAnalysis {
                       return std::min(S, I);
                     }),
                 EltsPerVector);
-            Indices.push_back(OffsetReg1 % NumElts);
+            unsigned __AlignedNumElts = alignTo(NumElts, EltsPerVector);
+            unsigned __MaxIdx = (__AlignedNumElts > EltsPerVector) ? (__AlignedNumElts - EltsPerVector) : 0u;
+            unsigned __Idx = std::min<unsigned>(OffsetReg1 % NumElts, __MaxIdx);
+            Indices.push_back(__Idx);
           }
           Idx = I - OffsetReg1;
         }

